package com.vidaysalud.veterinaria.medicamentoservicio.model;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;@Entity @Table(name="medicamento",uniqueConstraints=@UniqueConstraint(name="uq_medicamento_nombre",columnNames="nombre")) @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Medicamento{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="id_medicamento") private Integer idMedicamento;@Column(nullable=false,length=100,unique=true) private String nombre;@Lob private String descripcion;@Column(nullable=false) private Integer stock;@Column(name="precio_unitario",nullable=false,precision=10,scale=2) private BigDecimal precioUnitario;@Column(nullable=false) private Boolean activo;@PrePersist void pre(){if(stock==null)stock=0;if(precioUnitario==null)precioUnitario=BigDecimal.ZERO;if(activo==null)activo=true;}}